import hashlib
from spyne import Application, rpc, ServiceBase, Integer, Unicode, Decimal
from spyne.protocol.soap import Soap11
from spyne.server.wsgi import WsgiApplication
from wsgiref.simple_server import make_server
from spyne.model.complex import ComplexModel
from spyne.model.fault import Fault
from spyne.decorator import rpc as spyne_rpc
from lxml import etree


class AccountInfo(ComplexModel):
    account_number = Unicode
    account_holder = Unicode
    account_type = Unicode
    balance = Decimal


class TransferResult(ComplexModel):
    success = Unicode
    transaction_id = Unicode
    message = Unicode


class SoapActionSpoofingError(Fault):
    def __init__(self):
        super(SoapActionSpoofingError, self).__init__(
            faultcode='Client.SoapActionMismatch',
            faultstring='SOAPAction header does not match the requested operation'
        )


accounts_db = {
    '1001': {'holder': 'John Doe', 'type': 'Savings', 'balance': 5000.00},
    '1002': {'holder': 'Jane Smith', 'type': 'Checking', 'balance': 3500.00},
    '1003': {'holder': 'Bob Johnson', 'type': 'Savings', 'balance': 10000.00}
}


class FinancialService(ServiceBase):
    @spyne_rpc(Unicode, _returns=Decimal, _operation_name='getBalance')
    def get_balance(ctx, account_number):
        soap_action = ctx.in_header_doc.get('SOAPAction', '')
        expected_action = '"getBalance"'
        
        if soap_action != expected_action:
            raise SoapActionSpoofingError()
        
        if account_number in accounts_db:
            return Decimal(str(accounts_db[account_number]['balance']))
        else:
            raise Fault(faultcode='Client.AccountNotFound',
                       faultstring='Account not found')

    @spyne_rpc(Unicode, Unicode, Decimal, _returns=TransferResult, 
               _operation_name='transferFunds')
    def transfer_funds(ctx, from_account, to_account, amount):
        soap_action = ctx.in_header_doc.get('SOAPAction', '')
        expected_action = '"transferFunds"'
        
        if soap_action != expected_action:
            raise SoapActionSpoofingError()
        
        if from_account not in accounts_db:
            raise Fault(faultcode='Client.AccountNotFound',
                       faultstring='Source account not found')
        
        if to_account not in accounts_db:
            raise Fault(faultcode='Client.AccountNotFound',
                       faultstring='Destination account not found')
        
        if accounts_db[from_account]['balance'] < float(amount):
            raise Fault(faultcode='Client.InsufficientFunds',
                       faultstring='Insufficient funds')
        
        accounts_db[from_account]['balance'] -= float(amount)
        accounts_db[to_account]['balance'] += float(amount)
        
        transaction_id = hashlib.sha256(
            f"{from_account}{to_account}{amount}".encode()
        ).hexdigest()[:16]
        
        result = TransferResult()
        result.success = 'true'
        result.transaction_id = transaction_id
        result.message = f'Successfully transferred {amount} from {from_account} to {to_account}'
        
        return result

    @spyne_rpc(Unicode, _returns=AccountInfo, _operation_name='getAccountInfo')
    def get_account_info(ctx, account_number):
        soap_action = ctx.in_header_doc.get('SOAPAction', '')
        expected_action = '"getAccountInfo"'
        
        if soap_action != expected_action:
            raise SoapActionSpoofingError()
        
        if account_number in accounts_db:
            account = accounts_db[account_number]
            info = AccountInfo()
            info.account_number = account_number
            info.account_holder = account['holder']
            info.account_type = account['type']
            info.balance = Decimal(str(account['balance']))
            return info
        else:
            raise Fault(faultcode='Client.AccountNotFound',
                       faultstring='Account not found')


class SoapActionValidationMiddleware:
    def __init__(self, app):
        self.app = app

    def __call__(self, environ, start_response):
        soap_action = environ.get('HTTP_SOAPACTION', '').strip('"')
        
        if environ['REQUEST_METHOD'] == 'POST':
            content_length = int(environ.get('CONTENT_LENGTH', 0))
            body = environ['wsgi.input'].read(content_length)
            
            try:
                root = etree.fromstring(body)
                namespaces = {
                    'soap': 'http://schemas.xmlsoap.org/soap/envelope/',
                    'tns': 'spyne.examples.financial'
                }
                
                body_element = root.find('.//soap:Body', namespaces)
                if body_element is not None:
                    operation_element = None
                    for child in body_element:
                        if child.tag.endswith('getBalance') or \
                           child.tag.endswith('transferFunds') or \
                           child.tag.endswith('getAccountInfo'):
                            operation_element = child
                            break
                    
                    if operation_element is not None:
                        operation_name = operation_element.tag.split('}')[-1]
                        
                        if soap_action and soap_action != operation_name:
                            response_body = f'''<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
    <soap:Body>
        <soap:Fault>
            <faultcode>Client.SoapActionMismatch</faultcode>
            <faultstring>SOAPAction header does not match the requested operation</faultstring>
        </soap:Fault>
    </soap:Body>
</soap:Envelope>'''
                            
                            status = '500 Internal Server Error'
                            response_headers = [
                                ('Content-Type', 'text/xml; charset=utf-8'),
                                ('Content-Length', str(len(response_body)))
                            ]
                            start_response(status, response_headers)
                            return [response_body.encode('utf-8')]
                        
                        environ['in_header_doc'] = {'SOAPAction': f'"{soap_action}"'}
            
            except Exception as e:
                pass
            
            from io import BytesIO
            environ['wsgi.input'] = BytesIO(body)
        
        return self.app(environ, start_response)


def create_soap_application():
    application = Application(
        [FinancialService],
        tns='spyne.examples.financial',
        in_protocol=Soap11(validator='lxml'),
        out_protocol=Soap11()
    )
    
    wsgi_app = WsgiApplication(application)
    
    wrapped_app = SoapActionValidationMiddleware(wsgi_app)
    
    return wrapped_app


